// ── Group Classifier ──
export const sedGetGroup = c => {
  if (c.includes("Local Anesthetic")) return "Local Anesthetics";
  if (c.includes("Topical")) return "Topical Anesthetics";
  if (c.includes("Nitrous") || c.includes("N₂O")) return "Nitrous Oxide";
  if (c.includes("Oral Anxiolysis") || c.includes("Oral Sedation")) return "Oral Anxiolysis";
  if (c.includes("IV Sedation") || c.includes("Intravenous")) return "IV Sedation";
  if (c.includes("Emergency")) return "Emergency Drugs";
  if (c.includes("Technique") || c.includes("Injection")) return "Injection Techniques";
  if (c.includes("Reversal") || c.includes("Buffered")) return "Adjuncts & Reversal";
  if (c.includes("Delivery System") || c.includes("CCLAD")) return "Delivery Systems";
  if (c.includes("Protocol") || c.includes("Algorithm") || c.includes("Max Dose")) return "Protocols & Dose Calculations";
  return "Other";
};

export const SED_GROUPS = ["Local Anesthetics", "Topical Anesthetics", "Nitrous Oxide", "Oral Anxiolysis", "IV Sedation", "Emergency Drugs", "Injection Techniques", "Delivery Systems", "Adjuncts & Reversal", "Protocols & Dose Calculations"];

